// Helper to convert price string to number
const parsePrice = (price) => {
  if (!price) return 0;
  return parseInt(price.toString().replace(/[₹,]/g, ''));
}
const convert = (p, gender) => ({
  name:          p.name,
  price:         parsePrice(p.price),
  originalPrice: parsePrice(p.originalPrice),
  rating:        p.rating || 0,
  tag:           p.tag || null,
  category:      p.category,
  brand:         p.brand,
  sizes:         p.size || [],
  color:         p.color || '',
  image:         p.img || '',
  gender:        gender
})

