const allProducts = [
  ...menRaw.map(p => convert(p, 'Men')),
  ...womenRaw.map(p => convert(p, 'Women')),
...footwearRaw.map(p => ({
  name: p.name,
  price: parsePrice(p.price),
  originalPrice: parsePrice(p.originalPrice),
  rating: p.rating || 0,
  tag: p.tag || null,
  category: p.category,
  brand: p.brand,
  sizes: p.size || [],
  color: p.color || '',
  image: p.img || '',
  gender: 'Footwear',
  subGender: p.gender || 'Men'  // ← original gender from data
})),
...accessoriesRaw.map(p => ({
  name: p.name,
  price: parsePrice(p.price),
  originalPrice: parsePrice(p.originalPrice),
  rating: p.rating || 0,
  tag: p.tag || null,
  category: p.category,
  brand: p.brand,
  sizes: p.size || [],
  color: p.color || '',
  image: p.img || '',
  gender: 'Accessories',
  subGender: p.gender || 'Men'  // ← original gender from data
})),]

mongoose.connect(process.env.MONGO_URI)
  .then(async () => {
    console.log('MongoDB connected');
    await Product.deleteMany();
    await Product.insertMany(allProducts);
    console.log(`✅ ${allProducts.length} products imported!`);
    process.exit();
  })
  .catch(err => {
    console.log(err);
    process.exit(1);
  });